namespace sv_e3e41eeb22fd4978838494fef51724ec.Services;

public class WarehouseState
{
    public static readonly IReadOnlyList<(string Id, string Name)> Warehouses =
    [
        ("WH-001", "Warehouse A — Main"),
        ("WH-002", "Warehouse B — East"),
        ("WH-003", "Warehouse C — West"),
        ("WH-004", "Warehouse D — South"),
    ];

    private string _currentWarehouseId = Warehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        Warehouses.First(w => w.Id == _currentWarehouseId).Name;

    public int LowStockCount { get; private set; }

    public event Action? OnWarehouseChanged;
    public event Action? OnAlertCountChanged;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId != warehouseId)
        {
            _currentWarehouseId = warehouseId;
            LowStockCount = 0;
            OnWarehouseChanged?.Invoke();
        }
    }

    public void UpdateAlertCount(int count)
    {
        LowStockCount = count;
        OnAlertCountChanged?.Invoke();
    }
}

namespace sv_e3e41eeb22fd4978838494fef51724ec.Services;

public class InventoryAlertService
{
    private readonly Random _random = new();

    /// <summary>
    /// Simulates a database query for items below minimum stock levels.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }
}

@inject WarehouseState WarehouseState

<div class="d-flex align-items-center">
    <label class="me-2 text-nowrap fw-semibold" for="warehouse-select">Warehouse:</label>
    <select id="warehouse-select"
            class="form-select form-select-sm"
            style="width: auto;"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnChanged">
        @foreach (var (id, name) in WarehouseState.Warehouses)
        {
            <option value="@id">@name</option>
        }
    </select>
</div>

@code {
    private void OnChanged(ChangeEventArgs e)
    {
        if (e.Value?.ToString() is { Length: > 0 } id)
        {
            WarehouseState.SetWarehouse(id);
        }
    }
}

@inject WarehouseState WarehouseState
@implements IDisposable

@if (WarehouseState.LowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@WarehouseState.LowStockCount</span>
}

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnAlertCountChanged += HandleAlertChanged;
    }

    private async void HandleAlertChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnAlertCountChanged -= HandleAlertChanged;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard — @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>
<h4 class="text-muted mb-4">@WarehouseState.CurrentWarehouseName</h4>

<div class="row">
    <div class="col-md-4 mb-3">
        <div class="card @(_lowStockCount > 0 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low Stock Alerts</h5>
                <p class="display-4 @(_lowStockCount > 0 ? "text-danger" : "text-success")">
                    @_lowStockCount
                </p>
                <p class="text-muted">items below minimum level</p>
            </div>
        </div>
    </div>
</div>

<p class="text-muted">
    <small>Refreshes every 10 seconds · Last updated: @_lastUpdated?.ToString("HH:mm:ss")</small>
</p>

@code {
    private int _lowStockCount;
    private DateTime? _lastUpdated;
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnWarehouseChanged += OnWarehouseChanged;
        await RefreshAlerts();
        StartPolling();
    }

    private void StartPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        _ = PollAsync(_cts.Token);
    }

    private async Task PollAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await RefreshAlerts();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose or warehouse change
        }
    }

    private async Task RefreshAlerts()
    {
        _lowStockCount = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        _lastUpdated = DateTime.Now;
        WarehouseState.UpdateAlertCount(_lowStockCount);
        await InvokeAsync(StateHasChanged);
    }

    private async void OnWarehouseChanged()
    {
        StartPolling();
        await RefreshAlerts();
    }

    public void Dispose()
    {
        WarehouseState.OnWarehouseChanged -= OnWarehouseChanged;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

